import { useEffect, useRef, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { motion } from 'framer-motion'
import { supabase } from '@/lib/supabase'
import { useAuthStore } from '@/store/useAuthStore'
import { useFilterStore } from '@/store/useFilterStore'
import { loadFilteredVocab, pickRandom, shuffle, type VocabCard } from '@/lib/vocab'
import { awardXp } from '@/lib/xp'
import { unlockAchievement } from '@/lib/achievements'
import { Header } from '@/components/Header'
import { XPToast, type XpToastData } from '@/components/XPToast'
import { ScoreScreen } from '@/components/ScoreScreen'

// Modus 4 — Speedround 60s laut CLAUDE.md §6.4.
//   - Timer startet bei 60s, schrumpft kontinuierlich
//   - HU-Wort + 4 DE-Optionen (eine korrekt, drei Distraktoren)
//   - Korrekt: +5 XP × Combo, +0.5s Timer-Bonus, Combo +1
//   - Falsch: -2s, Combo reset auf 0, +0 XP
//   - Game-Over wenn Timer 0
//   - Personal Best in study_sessions.metadata.best_speedround_score

const START_TIME = 60
const CORRECT_BONUS_S = 0.5
const WRONG_PENALTY_S = 2.0

type Question = {
  card: VocabCard
  options: string[]
  correctIndex: number
}

export default function Speedround() {
  const { user } = useAuthStore()
  const filter = useFilterStore()
  const navigate = useNavigate()

  const [pool, setPool] = useState<VocabCard[] | null>(null)
  const [question, setQuestion] = useState<Question | null>(null)
  const [timeLeft, setTimeLeft] = useState(START_TIME)
  const [score, setScore] = useState(0)
  const [combo, setCombo] = useState(0)
  const [correct, setCorrect] = useState(0)
  const [wrong, setWrong] = useState(0)
  const [picked, setPicked] = useState<{ idx: number; correct: boolean } | null>(null)
  const [done, setDone] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [previousBest, setPreviousBest] = useState<number | null>(null)

  const timerRef = useRef<number | null>(null)

  // Pool + previous best laden
  useEffect(() => {
    let cancelled = false
    async function load() {
      try {
        const cards = await loadFilteredVocab(filter, user?.id ?? null)
        if (cancelled) return
        if (cards.length < 4) {
          setError(`Zu wenige Karten gefunden (${cards.length}). Andere Filter probieren.`)
          return
        }
        setPool(cards)

        if (user) {
          const { data } = await supabase
            .from('study_sessions')
            .select('metadata')
            .eq('user_id', user.id)
            .eq('game_type', 'speedround')
            .order('started_at', { ascending: false })
            .limit(20)
          const best = (data ?? []).reduce<number>((acc, row) => {
            const m = (row as { metadata: { score?: number } | null }).metadata
            return Math.max(acc, m?.score ?? 0)
          }, 0)
          setPreviousBest(best)
        }
      } catch (e) {
        setError(String((e as Error).message ?? e))
      }
    }
    void load()
    return () => { cancelled = true }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, filter.category, filter.wordClass, filter.difficulty, filter.mastery])

  // Erste Frage laden
  useEffect(() => {
    if (!pool) return
    setQuestion(makeQuestion(pool))
    setTimeLeft(START_TIME)
    setScore(0)
    setCombo(0)
    setCorrect(0)
    setWrong(0)
    setDone(false)
  }, [pool])

  // Timer-Interval
  useEffect(() => {
    if (!question || done) return
    const start = performance.now()
    let last = timeLeft

    function tick(now: number) {
      const elapsed = (now - start) / 1000
      const next = Math.max(0, last - elapsed)
      setTimeLeft(next)
      if (next <= 0) {
        setDone(true)
        return
      }
      timerRef.current = requestAnimationFrame(tick)
    }
    timerRef.current = requestAnimationFrame(tick)
    return () => {
      if (timerRef.current) cancelAnimationFrame(timerRef.current)
    }
    // Reset whenever question wechselt (last = aktueller Wert).
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [question, done])

  // Save best score wenn done
  useEffect(() => {
    if (!done || !user) return
    void awardXp({ baseAmount: score, source: 'speedround_session', mode: 'medical' })
      .then((r) => r && setToast({ id: Date.now(), ...r }))
    if (correct >= 50) {
      void unlockAchievement('speedrun_50')
    }
    void supabase.from('study_sessions').insert({
      user_id: user.id,
      app: 'virag',
      mode: 'medical',
      game_type: 'speedround',
      ended_at: new Date().toISOString(),
      cards_reviewed: correct + wrong,
      correct_count: correct,
      xp_earned: score,
      metadata: { score, combo_max: combo, correct, wrong }
    })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [done])

  function handlePick(idx: number) {
    if (!question || picked || done) return
    const isCorrect = idx === question.correctIndex
    setPicked({ idx, correct: isCorrect })

    if (isCorrect) {
      const newCombo = combo + 1
      const gained = 5 * newCombo
      setCombo(newCombo)
      setCorrect((c) => c + 1)
      setScore((s) => s + gained)
      setTimeLeft((t) => Math.min(START_TIME, t + CORRECT_BONUS_S))
    } else {
      setCombo(0)
      setWrong((w) => w + 1)
      setTimeLeft((t) => Math.max(0, t - WRONG_PENALTY_S))
    }

    // Nächste Frage nach kurzer Visualisierung
    setTimeout(() => {
      if (!pool) return
      setPicked(null)
      setQuestion(makeQuestion(pool))
    }, 350)
  }

  useEffect(() => {
    if (!toast) return
    const t = setTimeout(() => setToast(null), 1200)
    return () => clearTimeout(t)
  }, [toast])

  function restart() {
    if (!pool) return
    setQuestion(makeQuestion(pool))
    setTimeLeft(START_TIME)
    setScore(0)
    setCombo(0)
    setCorrect(0)
    setWrong(0)
    setPicked(null)
    setDone(false)
  }

  if (error) {
    return <Wrapper><Status>⚠ {error}</Status><button onClick={() => navigate('/home')} style={btnGhost}>Zurück</button></Wrapper>
  }
  if (!pool || !question) return <Wrapper><Status>Karten werden geladen…</Status></Wrapper>

  if (done) {
    const isNewBest = previousBest !== null && score > previousBest
    return (
      <ScoreScreen
        emoji={isNewBest ? '🏆' : '⏱️'}
        title={isNewBest ? 'Neuer Highscore!' : 'Zeit abgelaufen'}
        subtitle={isNewBest && previousBest !== null
          ? `${score} XP — vorher ${previousBest}`
          : previousBest !== null && previousBest > 0
            ? `Highscore: ${previousBest} XP`
            : undefined}
        stats={[
          { label: 'Score', value: score, highlight: true },
          { label: 'Richtig / Falsch', value: `${correct} / ${wrong}` },
          { label: 'Beste Combo', value: combo }
        ]}
        totalXp={score}
        primaryAction={{ label: 'Nochmal', onClick: restart }}
        secondaryAction={{ label: 'Zurück zu Home', onClick: () => navigate('/home') }}
      />
    )
  }

  const timerPercent = (timeLeft / START_TIME) * 100
  const timerColor = timeLeft < 10 ? 'var(--red)' : timeLeft < 20 ? 'var(--orange)' : 'var(--green)'

  return (
    <Wrapper>
      <div style={{ width: '100%', maxWidth: 480, marginBottom: '0.7rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.85rem', opacity: 0.75 }}>
          <span>{score} XP · Combo ×{combo}</span>
          <span>{timeLeft.toFixed(1)} s</span>
        </div>
        <div style={{ height: 6, background: 'rgba(0,0,0,0.07)', borderRadius: 999, marginTop: 4, overflow: 'hidden' }}>
          <div
            style={{
              width: `${timerPercent}%`,
              height: '100%',
              background: timerColor,
              transition: 'width 100ms linear, background 200ms'
            }}
          />
        </div>
      </div>

      <div
        style={{
          width: '100%',
          maxWidth: 480,
          background: 'var(--white)',
          border: '2px solid var(--red)',
          borderRadius: 14,
          padding: '1.5rem 1rem',
          textAlign: 'center',
          boxShadow: 'var(--shadow-card)'
        }}
      >
        <div className="hu-vocab" style={{ color: 'var(--red)' }}>{question.card.hungarian}</div>
        {question.card.phonetic && (
          <div className="phonetic" style={{ marginTop: 4, fontSize: '0.9rem' }}>[{question.card.phonetic}]</div>
        )}
      </div>

      <div
        style={{
          width: '100%',
          maxWidth: 480,
          marginTop: '0.9rem',
          display: 'grid',
          gridTemplateColumns: '1fr 1fr',
          gap: 8
        }}
      >
        {question.options.map((opt, i) => {
          const isCorrectChoice = picked && i === question.correctIndex
          const isWrongChoice = picked && picked.idx === i && !picked.correct
          const bg =
            isCorrectChoice ? 'var(--green)' :
            isWrongChoice ? 'var(--red)' : 'var(--white)'
          const color = isCorrectChoice || isWrongChoice ? 'var(--cream)' : 'inherit'
          const border = isCorrectChoice ? 'var(--green)' : isWrongChoice ? 'var(--red)' : 'rgba(0,0,0,0.15)'

          return (
            <motion.button
              key={i}
              animate={isWrongChoice ? { x: [0, -5, 5, -5, 5, 0] } : {}}
              transition={{ duration: 0.35 }}
              onClick={() => handlePick(i)}
              disabled={!!picked}
              style={{
                background: bg,
                color,
                border: `2px solid ${border}`,
                padding: '0.85rem',
                borderRadius: 12,
                fontFamily: 'inherit',
                fontSize: '0.95rem',
                fontWeight: 600,
                cursor: picked ? 'default' : 'pointer',
                minHeight: 60,
                transition: 'background 150ms, border-color 150ms'
              }}
            >
              {opt}
            </motion.button>
          )
        })}
      </div>

      <button onClick={() => navigate('/home')} style={{ ...btnGhost, marginTop: '1.5rem' }}>
        Sitzung abbrechen
      </button>

      <XPToast toast={toast} />
    </Wrapper>
  )
}

function makeQuestion(pool: VocabCard[]): Question {
  const card = pool[Math.floor(Math.random() * pool.length)]
  // Distraktoren: 3 zufällige andere Cards (keine Duplikate, andere ID)
  const others = pool.filter((c) => c.id !== card.id && c.german.toLowerCase() !== card.german.toLowerCase())
  const distractors = pickRandom(others, 3).map((c) => c.german)
  const options = shuffle([card.german, ...distractors])
  return {
    card,
    options,
    correctIndex: options.indexOf(card.german)
  }
}

function Wrapper({ children }: { children: React.ReactNode }) {
  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}>
      <Header />
      <main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '1.5rem 1rem 3rem' }}>
        {children}
      </main>
    </div>
  )
}

function Status({ children }: { children: React.ReactNode }) {
  return <div style={{ opacity: 0.55, fontSize: '0.95rem', marginTop: '20vh' }}>{children}</div>
}

const btnGhost: React.CSSProperties = {
  background: 'none',
  border: '1.5px solid rgba(0,0,0,0.15)',
  padding: '0.45rem 0.9rem',
  borderRadius: 8,
  fontFamily: 'inherit',
  fontSize: '0.8rem',
  cursor: 'pointer',
  opacity: 0.65
}
